import openpyxl
from openpyxl.styles import PatternFill, Alignment

wb = openpyxl.load_workbook('input.xlsx')
ws = wb.active
ws.title = 'Sheet1'

# Identify races (rows where B == 1)
race_starts = []
for r in range(2, ws.max_row + 1):
    b_val = ws.cell(r, 2).value
    if b_val is not None and int(b_val) == 1:
        c_val = int(ws.cell(r, 3).value)
        race_starts.append((r, c_val))

# Transpose G values into H:S for each race
for start_row, num_runners in race_starts:
    for i in range(num_runners):
        src_row = start_row + i
        g_val = ws.cell(src_row, 7).value  # Column G
        target_col = 8 + i  # H=8
        if target_col <= 19:  # S=19
            if g_val is not None and str(g_val).strip() != '':
                try:
                    num = float(g_val)
                    if num == int(num):
                        ws.cell(start_row, target_col).value = int(num)
                    else:
                        ws.cell(start_row, target_col).value = num
                except (ValueError, TypeError):
                    ws.cell(start_row, target_col).value = g_val
            else:
                ws.cell(start_row, target_col).value = None  # blank stays blank

# Shade H2:S28 with #E2EFDA
fill = PatternFill(start_color='E2EFDA', end_color='E2EFDA', fill_type='solid')
for r in range(2, 29):
    for c in range(8, 20):
        ws.cell(r, c).fill = fill

# Remove decimals for whole values in H2:S28 (re-check all cells)
for r in range(2, 29):
    for c in range(8, 20):
        cell = ws.cell(r, c)
        v = cell.value
        if v is not None:
            try:
                num = float(v)
                if num == int(num):
                    cell.value = int(num)
                    cell.number_format = '0'
                else:
                    cell.number_format = '0.0###'
            except (ValueError, TypeError):
                pass

# Center align all cells to the right of column G (H onwards), all rows
for r in range(1, ws.max_row + 1):
    for c in range(8, max(ws.max_column + 1, 20)):
        ws.cell(r, c).alignment = Alignment(horizontal='center', vertical='center')

wb.save('output.xlsx')
print("Done!")

# Verify
